import React from "react";
import {ConfirmPopup} from "primereact/confirmpopup";
import type {IConfirmPopupProps} from "@lmb-it/kitsconcerto-types";

export default function KitsConfirmPopup(props: IConfirmPopupProps & { onHide?: () => void }) {
    const {visible, onHide, ...rest} = props;

    return (
        <ConfirmPopup
            {...rest}
            visible={visible}
            onHide={() => onHide?.()}
        />
    );
}
